import React, { useState, useEffect, useCallback } from 'react';
import usePageTitle from '../hooks/usePageTitle';
import { api, apiPost } from '../utils/api';
import s from './SelfHealingPage.module.css';

/* ── Helpers ─────────────────────────────────────────────────────────────── */
function timeAgo(ts) {
  if (!ts) return 'never';
  const ms = typeof ts === 'number' && ts < 1e12 ? ts * 1000 : new Date(ts).getTime();
  const diff = Date.now() - ms;
  const secs = Math.floor(diff / 1000);
  if (secs < 0) return 'just now';
  if (secs < 60) return secs + 's ago';
  const mins = Math.floor(secs / 60);
  if (mins < 60) return mins + 'm ago';
  const hrs = Math.floor(mins / 60);
  if (hrs < 24) return hrs + 'h ago';
  return Math.floor(hrs / 24) + 'd ago';
}

function formatTs(ts) {
  if (!ts) return '--';
  try {
    const ms = typeof ts === 'number' && ts < 1e12 ? ts * 1000 : new Date(ts).getTime();
    return new Date(ms).toLocaleString('en-US', {
      month: 'short', day: 'numeric', hour: '2-digit', minute: '2-digit', second: '2-digit',
    });
  } catch { return '--'; }
}

/* ── Color constants (for dynamic inline styles) ─────────────────────────── */
const C = {
  green: 'var(--color-green, #22C55E)',
  red: 'var(--color-red, #EF4444)',
  amber: 'var(--color-amber, #F59E0B)',
  textSecondary: 'var(--color-text-secondary, #90A3AF)',
};

/* ── Status Pill ─────────────────────────────────────────────────────────── */
function StatusPill({ label, color }) {
  const c = color || C.textSecondary;
  return (
    <span className={s.statusPill} style={{ color: c, background: `${c}12`, border: `1px solid ${c}25` }}>
      <span className={s.statusPillDot} style={{ background: c, boxShadow: `0 0 6px ${c}50` }} />
      {label}
    </span>
  );
}

/* ── Toggle Switch ───────────────────────────────────────────────────────── */
function ToggleSwitch({ enabled, onToggle, saving }) {
  return (
    <button
      onClick={onToggle}
      disabled={saving}
      className={enabled ? s.toggleEnabled : s.toggleDisabled}
      style={saving ? { opacity: 0.5 } : undefined}
    >
      <span className={enabled ? s.toggleThumbOn : s.toggleThumbOff} />
    </button>
  );
}

/* ── Default healer definitions (used when API returns empty) ────────────── */
const DEFAULT_HEALERS = [
  { id: 'container_crash_loop', name: 'Container Crash Loop', trigger: 'Container restart count > 3 in 5min', enabled: true, cooldown_remaining: 0, last_execution: null },
  { id: 'api_latency_spike', name: 'API Latency Spike', trigger: 'P95 latency > 2000ms for 60s', enabled: true, cooldown_remaining: 0, last_execution: null },
  { id: 'error_rate_spike', name: 'Error Rate Spike', trigger: 'Error rate > 5% for 120s', enabled: true, cooldown_remaining: 0, last_execution: null },
  { id: 'queue_backlog', name: 'Queue Backlog', trigger: 'Queue depth > 100 for 180s', enabled: true, cooldown_remaining: 0, last_execution: null },
  { id: 'disk_memory_pressure', name: 'Disk/Memory Pressure', trigger: 'Memory > 85% or Disk > 90%', enabled: true, cooldown_remaining: 0, last_execution: null },
  { id: 'ibkr_gateway', name: 'IBKR Gateway', trigger: 'Gateway disconnected > 30s', enabled: true, cooldown_remaining: 0, last_execution: null, trading: true },
];

/* ── Safety classification rules ─────────────────────────────────────────── */
const SAFETY_RULES = {
  AUTO: [
    'Restart crashed containers',
    'Clear expired cache entries',
    'Rotate log files',
    'Scale up workers for queue backlog',
    'Restart API on sustained latency spike',
  ],
  GUARDED: [
    'Restart IBKR Gateway',
    'Force reconnect trading sessions',
    'Kill and restart bot processes',
    'Purge and rebuild Redis cache',
    'Restart database connections',
  ],
  FORBIDDEN: [
    'Disable trading kill switch',
    'Modify position sizing',
    'Place or cancel orders',
    'Change risk parameters',
    'Deploy code changes',
  ],
};

const CLASS_COLORS = { AUTO: C.green, GUARDED: C.amber, FORBIDDEN: C.red };

/* ═══════════════════════════════════════════════════════════════════════════
   SELF-HEALING PAGE
   ═══════════════════════════════════════════════════════════════════════════ */
export default function SelfHealingPage() {
  usePageTitle('Self-Healing Engine');

  const [healers, setHealers] = useState(DEFAULT_HEALERS);
  const [executions, setExecutions] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [togglingId, setTogglingId] = useState(null);
  const [engineActive, setEngineActive] = useState(true);

  const fetchAll = useCallback(async () => {
    try {
      const [healerData, execData] = await Promise.all([
        api('/self-heal/healers'),
        api('/self-heal/executions'),
      ]);
      if (healerData) {
        const list = Array.isArray(healerData) ? healerData : healerData.healers || [];
        if (list.length > 0) setHealers(list);
        if (healerData.engine_active !== undefined) setEngineActive(healerData.engine_active);
      }
      if (execData) {
        const list = Array.isArray(execData) ? execData : execData.executions || [];
        setExecutions(list.slice(0, 50));
      }
      setError(null);
    } catch (e) {
      setError(e.message);
    }
    setLoading(false);
  }, []);

  useEffect(() => {
    fetchAll();
    const iv = setInterval(fetchAll, 30000);
    return () => clearInterval(iv);
  }, [fetchAll]);

  const handleToggle = async (healerId) => {
    setTogglingId(healerId);
    const result = await apiPost(`/self-heal/healers/${healerId}/toggle`);
    if (result) {
      setHealers(prev => prev.map(h =>
        h.id === healerId ? { ...h, enabled: !h.enabled } : h
      ));
    }
    setTogglingId(null);
  };

  const activeCount = healers.filter(h => h.enabled).length;

  return (
    <div className={s.page}>

      {/* ── Header ──────────────────────────────────────────────────────── */}
      <div className={s.header}>
        <div>
          <h1 className={s.headerTitle}>Self-Healing Engine</h1>
          <p className={s.headerSubtitle}>
            Automated failure detection, classification, and remediation
          </p>
        </div>
        <div className={s.headerRight}>
          <StatusPill
            label={engineActive ? 'ACTIVE' : 'PAUSED'}
            color={engineActive ? C.green : C.amber}
          />
          <div className={s.headerMeta}>
            {activeCount}/{healers.length} healers enabled
          </div>
        </div>
      </div>

      {error && (
        <div className={s.errorBanner}>
          Failed to load: {typeof error === 'string' ? error : 'An error occurred'}
        </div>
      )}

      {/* ── Main Content: Healers Grid + Safety Rules ───────────────────── */}
      <div className={s.mainGrid}>

        {/* ── Healers Grid ─────────────────────────────────────────────── */}
        <div>
          <div className={s.sectionHeader}>Healers</div>
          <div className={s.healersGrid}>
            {healers.map(healer => {
              const isTrading = healer.trading || healer.id === 'ibkr_gateway';
              const onCooldown = healer.cooldown_remaining > 0;
              const borderColor = healer.enabled ? C.green : 'var(--color-border, rgba(255,255,255,0.06))';

              return (
                <div key={healer.id} className={s.healerCard} style={{ borderTop: `3px solid ${borderColor}` }}>
                  {/* Trading badge */}
                  {isTrading && <span className={s.tradingBadge}>TRADING</span>}

                  {/* Name + toggle */}
                  <div className={s.healerHeader}>
                    <div className={s.healerNameGroup}>
                      <span className={healer.enabled ? s.healerDotEnabled : s.healerDotDisabled} />
                      <span className={s.healerName}>{healer.name}</span>
                    </div>
                    <ToggleSwitch
                      enabled={healer.enabled}
                      onToggle={() => handleToggle(healer.id)}
                      saving={togglingId === healer.id}
                    />
                  </div>

                  {/* Trigger condition */}
                  <div className={s.healerTrigger}>
                    {typeof healer.trigger === 'string' ? healer.trigger
                      : healer.trigger_condition
                        ? healer.trigger_condition
                        : healer.trigger && typeof healer.trigger === 'object'
                          ? (healer.trigger.description || healer.trigger.metric || JSON.stringify(healer.trigger))
                          : 'Condition not specified'}
                  </div>

                  {/* Stats row */}
                  <div className={s.healerStats}>
                    <div>
                      <div className={s.statLabel}>Cooldown</div>
                      <div className={onCooldown ? s.statValueCooldown : s.statValue}>
                        {onCooldown ? `${healer.cooldown_remaining}s` : 'Ready'}
                      </div>
                    </div>
                    <div>
                      <div className={s.statLabel}>Last Run</div>
                      <div className={s.statValue}>{timeAgo(healer.last_execution)}</div>
                    </div>
                    {healer.execution_count !== undefined && (
                      <div>
                        <div className={s.statLabel}>Runs</div>
                        <div className={s.statValue}>{healer.execution_count}</div>
                      </div>
                    )}
                  </div>
                </div>
              );
            })}
          </div>
        </div>

        {/* ── Safety Rules Panel ─────────────────────────────────────────── */}
        <div className={s.panel}>
          <div className={s.sectionHeader}>Safety Classification</div>
          {Object.entries(SAFETY_RULES).map(([classification, rules]) => {
            const classColor = CLASS_COLORS[classification];
            return (
              <div key={classification} className={s.classificationGroup}>
                <div
                  className={s.classificationBadge}
                  style={{ color: classColor, background: `${classColor}12`, border: `1px solid ${classColor}25` }}
                >
                  {classification}
                </div>
                <div className={s.rulesList}>
                  {rules.map((rule, i) => (
                    <div key={i} className={s.ruleItem} style={{ borderLeft: `2px solid ${classColor}30` }}>
                      {rule}
                    </div>
                  ))}
                </div>
              </div>
            );
          })}

          {/* Trading DISARM banner */}
          <div className={s.disarmBanner}>
            <div className={s.disarmTitle}>TRADING DISARM</div>
            <div className={s.disarmText}>
              Any GUARDED action involving trading infrastructure requires manual approval.
              Trading will be disarmed during execution.
            </div>
          </div>
        </div>
      </div>

      {/* ── Executions Table ─────────────────────────────────────────────── */}
      <div className={s.panel}>
        <div className={s.sectionHeader}>
          Execution Log
          <span className={s.execSectionMeta}>
            Last 50 executions | Auto-refresh 30s
          </span>
        </div>

        {executions.length === 0 ? (
          <div className={s.execEmpty}>
            {loading ? 'Loading executions...' : 'No executions recorded yet'}
          </div>
        ) : (
          <div className={s.execTableWrap}>
            <table className={s.execTable}>
              <thead>
                <tr className={s.execTableHead}>
                  {['Time', 'Healer', 'Action', 'Classification', 'Status', 'Result'].map(col => (
                    <th key={col} className={s.execTh}>{col}</th>
                  ))}
                </tr>
              </thead>
              <tbody>
                {executions.map((exec, i) => {
                  const classification = (exec.classification || 'AUTO').toUpperCase();
                  const classColor = classification === 'AUTO' ? C.green : C.amber;
                  const rawStatus = typeof exec.status === 'string' ? exec.status : (exec.status?.status || 'unknown');
                  const statusText = rawStatus.toLowerCase();
                  const statusCol = statusText === 'succeeded' || statusText === 'success' ? C.green
                    : statusText === 'failed' || statusText === 'error' ? C.red
                    : statusText === 'pending' ? C.amber
                    : C.textSecondary;

                  return (
                    <tr key={exec.id || i} className={s.execRow}>
                      <td className={s.execTdTime}>
                        {formatTs(exec.timestamp || exec.executed_at)}
                      </td>
                      <td className={s.execTdHealer}>
                        {exec.healer || exec.healer_name || '--'}
                      </td>
                      <td className={s.execTdAction}>
                        {exec.action || '--'}
                      </td>
                      <td className={s.execTd}>
                        <span
                          className={s.classBadge}
                          style={{ color: classColor, background: `${classColor}15`, border: `1px solid ${classColor}25` }}
                        >
                          {classification}
                        </span>
                      </td>
                      <td className={s.execTd}>
                        <span className={s.statusInline} style={{ color: statusCol }}>
                          <span className={s.statusInlineDot} style={{ background: statusCol }} />
                          {rawStatus}
                        </span>
                      </td>
                      <td className={s.execTdResult}>
                        {typeof exec.result === 'string' ? exec.result
                          : exec.result && typeof exec.result === 'object' ? (exec.result.status || JSON.stringify(exec.result))
                          : exec.message || '--'}
                      </td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>
        )}
      </div>
    </div>
  );
}
